+        bottom: u16,
+        count: u16,
+        scrollback: &mut Scrollback,
+    ) {
+        let top = top.min(self.rows);
+        let bottom = bottom.min(self.rows);
+        if top >= bottom || count == 0 {
+            return;
+        }
+        let count = count.min(bottom - top);
